(function() {
  function LightningEffect(canvas, options = {}) {
    const ctx = canvas.getContext('2d');
    let width, height;
    let animationId = null;
    let time = 0;
    let exploded = false;
    let explosionTime = 0;
    
    const config = {
      mainColor: "#FFFFFF",
      coreColor: "#A8E4FF",
      branchColor: "#0A74FF",
      glowColor: "#4FC3FF",
      lineWidth: 3,
      branchWidth: 2,
      ...options
    };
    
    let centerX = 0, centerY = 0;
    let corners = [];
    
    function resize() {
      width = canvas.clientWidth;
      height = canvas.clientHeight;
      canvas.width = width;
      canvas.height = height;
      
      centerX = width / 2;
      centerY = height / 2;
      
      // Recalcula os 4 cantos
      corners = [
        { x: 0, y: 0, progress: 0, active: true, arrived: false },
        { x: width, y: 0, progress: 0, active: true, arrived: false },
        { x: 0, y: height, progress: 0, active: true, arrived: false },
        { x: width, y: height, progress: 0, active: true, arrived: false }
      ];
      
      time = 0;
      exploded = false;
      explosionTime = 0;
    }
    
    // Desenha linha entre dois pontos com efeito de raio
    function drawLightningLine(p1, p2, isMain = true, offsetScale = 1) {
      const segments = 15;
      const points = [];
      
      // Gera pontos com zig-zag
      for (let i = 0; i <= segments; i++) {
        const t = i / segments;
        const x = p1.x + (p2.x - p1.x) * t;
        const y = p1.y + (p2.y - p1.y) * t;
        
        // Ruído para efeito de raio (mais intenso no meio)
        const noiseAmount = (isMain ? 25 : 15) * offsetScale * Math.sin(t * Math.PI);
        const noiseX = Math.sin(t * Math.PI * 4 + time * 25) * noiseAmount;
        const noiseY = Math.cos(t * Math.PI * 3 + time * 20) * noiseAmount;
        
        points.push({ x: x + noiseX, y: y + noiseY });
      }
      
      // Desenha o brilho (externo)
      ctx.beginPath();
      ctx.moveTo(points[0].x, points[0].y);
      for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x, points[i].y);
      }
      ctx.shadowBlur = isMain ? 15 : 8;
      ctx.shadowColor = config.glowColor;
      ctx.strokeStyle = isMain ? config.mainColor : config.branchColor;
      ctx.lineWidth = isMain ? config.lineWidth : config.branchWidth;
      ctx.stroke();
      
      // Núcleo branco
      if (isMain) {
        ctx.beginPath();
        ctx.moveTo(points[0].x, points[0].y);
        for (let i = 1; i < points.length; i++) {
          ctx.lineTo(points[i].x, points[i].y);
        }
        ctx.strokeStyle = "#FFFFFF";
        ctx.lineWidth = config.lineWidth * 0.4;
        ctx.stroke();
      }
      
      // Galhos (ramificações)
      if (isMain && offsetScale > 0.5) {
        const branchCount = 3;
        for (let b = 0; b < branchCount; b++) {
          const branchT = 0.2 + Math.random() * 0.6;
          const branchIdx = Math.floor(branchT * (points.length - 1));
          const branchPoint = points[branchIdx];
          
          // Direção do galho
          const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x) + (Math.random() - 0.5) * 1.5;
          const branchLen = 25 + Math.random() * 35;
          const endX = branchPoint.x + Math.cos(angle) * branchLen;
          const endY = branchPoint.y + Math.sin(angle) * branchLen;
          
          // Galho com zig-zag menor
          ctx.beginPath();
          ctx.moveTo(branchPoint.x, branchPoint.y);
          for (let s = 0; s <= 5; s++) {
            const st = s / 5;
            const bx = branchPoint.x + (endX - branchPoint.x) * st;
            const by = branchPoint.y + (endY - branchPoint.y) * st;
            const boffset = Math.sin(st * Math.PI * 4 + time * 30) * 5;
            ctx.lineTo(bx + boffset, by + boffset * 0.5);
          }
          ctx.strokeStyle = config.branchColor;
          ctx.lineWidth = config.branchWidth * 0.8;
          ctx.stroke();
        }
      }
    }
    
    // Desenha a explosão/formação do raio no centro
    function drawExplosion() {
      const intensity = Math.min(1, explosionTime * 4);
      const explosionProgress = Math.min(1, explosionTime * 2);
      
      // Círculo de explosão
      const radius = 10 + explosionProgress * 60;
      ctx.beginPath();
      const gradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, radius);
      gradient.addColorStop(0, `rgba(255, 255, 255, ${intensity})`);
      gradient.addColorStop(0.3, `rgba(79, 195, 255, ${intensity * 0.8})`);
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fill();
      
      // Raios saindo da explosão (formato de estrela/raio)
      const rayCount = 12;
      for (let i = 0; i < rayCount; i++) {
        const angle = (i / rayCount) * Math.PI * 2 + time * 10;
        const rayLength = 30 + explosionProgress * 80;
        const endX = centerX + Math.cos(angle) * rayLength * intensity;
        const endY = centerY + Math.sin(angle) * rayLength * intensity;
        
        // Raio com zig-zag
        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        
        for (let s = 0; s <= 8; s++) {
          const st = s / 8;
          const x = centerX + (endX - centerX) * st;
          const y = centerY + (endY - centerY) * st;
          const offset = Math.sin(st * Math.PI * 5 + time * 30) * (10 * intensity);
          const perpX = -(endY - centerY);
          const perpY = endX - centerX;
          const len = Math.sqrt(perpX * perpX + perpY * perpY);
          if (len > 0) {
            ctx.lineTo(x + (perpX / len) * offset, y + (perpY / len) * offset);
          } else {
            ctx.lineTo(x, y);
          }
        }
        
        ctx.strokeStyle = config.mainColor;
        ctx.lineWidth = config.lineWidth * (0.5 + intensity);
        ctx.shadowBlur = 12;
        ctx.stroke();
      }
      
      // Partículas da explosão
      const particleCount = 40;
      for (let i = 0; i < particleCount; i++) {
        const angle = Math.random() * Math.PI * 2;
        const dist = explosionProgress * (30 + Math.random() * 70);
        const x = centerX + Math.cos(angle) * dist;
        const y = centerY + Math.sin(angle) * dist;
        const life = Math.max(0, 1 - explosionProgress * 1.5);
        
        ctx.beginPath();
        ctx.arc(x, y, 2 + Math.random() * 3 * life, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${life * intensity})`;
        ctx.fill();
        
        ctx.beginPath();
        ctx.arc(x + (Math.random() - 0.5) * 8, y + (Math.random() - 0.5) * 8, 1.5, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(79, 195, 255, ${life * intensity * 0.7})`;
        ctx.fill();
      }
    }
    
    // Desenha as linhas dos cantos até o centro
    function drawCornerLines() {
      let allArrived = true;
      
      for (const corner of corners) {
        if (corner.active && !corner.arrived) {
          corner.progress += 0.015;
          
          if (corner.progress >= 1) {
            corner.progress = 1;
            corner.arrived = true;
          }
          allArrived = false;
        }
        
        const currentX = corner.x + (centerX - corner.x) * corner.progress;
        const currentY = corner.y + (centerY - corner.y) * corner.progress;
        
        // Desenha linha do canto até a posição atual
        const startPoint = { x: corner.x, y: corner.y };
        const endPoint = { x: currentX, y: currentY };
        
        // Quanto mais perto do centro, mais intenso
        const intensity = corner.progress;
        drawLightningLine(startPoint, endPoint, true, intensity);
        
        // Partícula na ponta
        ctx.beginPath();
        const gradient = ctx.createRadialGradient(currentX, currentY, 0, currentX, currentY, 6);
        gradient.addColorStop(0, '#FFFFFF');
        gradient.addColorStop(0.5, config.coreColor);
        gradient.addColorStop(1, config.glowColor);
        ctx.fillStyle = gradient;
        ctx.arc(currentX, currentY, 5, 0, Math.PI * 2);
        ctx.fill();
      }
      
      // Quando todas as linhas chegaram, ativa explosão
      if (allArrived && !exploded && corners[0].arrived) {
        exploded = true;
        explosionTime = 0;
      }
    }
    
    // Linhas de conexão entre os cantos (a linha que faltava)
    function drawConnections() {
      if (!exploded) return;
      
      // Conecta cantos opostos (formando um X)
      drawLightningLine(corners[0], corners[3], false, 0.8);
      drawLightningLine(corners[1], corners[2], false, 0.8);
      
      // Conecta cantos adjacentes (formando quadrado)
      drawLightningLine(corners[0], corners[1], false, 0.6);
      drawLightningLine(corners[1], corners[3], false, 0.6);
      drawLightningLine(corners[3], corners[2], false, 0.6);
      drawLightningLine(corners[2], corners[0], false, 0.6);
    }
    
    function animate() {
      if (!canvas.isConnected) {
        if (animationId) cancelAnimationFrame(animationId);
        return;
      }
      
      ctx.fillStyle = `rgba(0, 0, 0, 0.15)`;
      ctx.fillRect(0, 0, width, height);
      
      time += 0.016;
      
      // Desenha as linhas dos cantos
      drawCornerLines();
      
      // Desenha conexões entre cantos (a parte que faltava)
      drawConnections();
      
      // Gerencia a explosão
      if (exploded) {
        explosionTime += 0.025;
        drawExplosion();
        
        // Reseta após a explosão terminar
        if (explosionTime >= 1.5) {
          for (const corner of corners) {
            corner.progress = 0;
            corner.arrived = false;
            corner.active = true;
          }
          exploded = false;
          explosionTime = 0;
          time = 0;
        }
      }
      
      ctx.shadowBlur = 0;
      animationId = requestAnimationFrame(animate);
    }
    
    function init() {
      resize();
      window.addEventListener('resize', resize);
      animate();
    }
    
    init();
    
    return {
      dispose: () => {
        if (animationId) cancelAnimationFrame(animationId);
        window.removeEventListener('resize', resize);
      }
    };
  }
  
  window.TubesCursor = LightningEffect;
})();